// Both ensures pin `r1@.map_values(|e: EndPoint| e@).to_set()` and
// `r2@.map_values(|e: EndPoint| e@).to_set()` to the same value
// `self_@.dom()`. State the resulting transitive equality between the two
// mapped-view sets as a single quantifier-free implication so z3 does not
// need to instantiate any forall — this avoids the trigger-inference
// failure that the previous `assert forall|x: AbstractEndPoint| ...` block
// hit, and lines up the two ensures clauses with a common reduced term.
assert(
    (r1@.map_values(|e: EndPoint| e@).to_set() == self_@.dom()
     && r2@.map_values(|e: EndPoint| e@).to_set() == self_@.dom())
    ==> r1@.map_values(|e: EndPoint| e@).to_set()
        == r2@.map_values(|e: EndPoint| e@).to_set());
